WITH all_tables AS (SELECT ns.nspname AS object_schema, PG_GET_USERBYID(c.relowner) AS object_owner, 'TABLE' AS object_category, CASE WHEN c.relkind = 'r' THEN 'TABLE' WHEN c.relkind = 'S' THEN 'SEQUENCE' WHEN c.relkind = 'f' THEN 'FOREIGN_TABLE' WHEN c.relkind = 'p' THEN 'PARTITIONED_TABLE' WHEN c.relkind = 'c' THEN 'COMPOSITE_TYPE' WHEN c.relkind = 't' THEN 'TOAST_TABLE' ELSE 'UNCATEGORIZED_TABLE' END AS object_type FROM pg_class AS c JOIN pg_catalog.pg_namespace AS ns ON (c.relnamespace = ns.oid) WHERE ns.nspname <> ALL(ARRAY['pg_catalog', 'information_schema']) AND NOT ns.nspname ~ '^pg_toast' AND c.relkind = ANY(ARRAY['r', 'p', 'S', 'f', 'c', 't'])), all_views AS (SELECT ns.nspname AS object_schema, PG_GET_USERBYID(c.relowner) AS object_owner, 'VIEW' AS object_category, CASE WHEN c.relkind = 'v' THEN 'VIEW' WHEN c.relkind = 'm' THEN 'MATERIALIZED_VIEW' ELSE 'UNCATEGORIZED_VIEW' END AS object_type FROM pg_class AS c JOIN pg_catalog.pg_namespace AS ns ON (c.relnamespace = ns.oid) WHERE ns.nspname <> ALL(ARRAY['pg_catalog', 'information_schema']) AND NOT ns.nspname ~ '^pg_toast' AND c.relkind = ANY(ARRAY['v', 'm'])), all_indexes AS (SELECT ns.nspname AS object_schema, PG_GET_USERBYID(c.relowner) AS object_owner, 'INDEX' AS object_category, CASE WHEN c.relkind = 'I' AND NOT c.relname ~ '^pg_toast' THEN 'PARTITIONED_INDEX' WHEN c.relkind = 'I' AND c.relname ~ '^pg_toast' THEN 'TOAST_PARTITIONED_INDEX' WHEN c.relkind = 'i' AND NOT c.relname ~ '^pg_toast' THEN 'INDEX' WHEN c.relkind = 'i' AND c.relname ~ '^pg_toast' THEN 'TOAST_INDEX' ELSE 'UNCATEGORIZED_INDEX' END AS object_type FROM pg_index AS i JOIN pg_class AS c ON (i.indexrelid = c.oid) JOIN pg_catalog.pg_namespace AS ns ON (c.relnamespace = ns.oid) WHERE ns.nspname <> ALL(ARRAY['pg_catalog', 'information_schema']) AND NOT ns.nspname ~ '^pg_toast'), all_constraints AS (SELECT ns.nspname AS object_schema, PG_GET_USERBYID(c.relowner) AS object_owner, 'CONSTRAINT' AS object_category, CASE WHEN con.contype = 'c' THEN 'CHECK_CONSTRAINT' WHEN con.contype = 'f' THEN 'FOREIGN_KEY_CONSTRAINT' WHEN con.contype = 'p' THEN 'PRIMARY_KEY_CONSTRAINT' WHEN con.contype = 'u' THEN 'UNIQUE_CONSTRAINT' WHEN con.contype = 't' THEN 'CONSTRAINT_TRIGGER' WHEN con.contype = 'x' THEN 'EXCLUSION_CONSTRAINT' ELSE 'UNCATEGORIZED_CONSTRAINT' END AS object_type FROM pg_constraint AS con JOIN pg_class AS c ON con.conrelid = c.oid JOIN pg_catalog.pg_namespace AS ns ON (con.connamespace = ns.oid) WHERE ns.nspname <> ALL(ARRAY['pg_catalog', 'information_schema']) AND NOT ns.nspname ~ '^pg_toast'), all_triggers AS (SELECT ns.nspname AS object_schema, PG_GET_USERBYID(c.relowner) AS object_owner, 'TRIGGER' AS object_category, CASE CAST(t.tgtype AS INT) & 66 WHEN 2 THEN 'BEFORE' WHEN 64 THEN 'INSTEAD_OF' ELSE 'AFTER' END || '_' || CASE CAST(t.tgtype AS INT) & CAST(28 AS SMALLINT) WHEN 16 THEN 'UPDATE' WHEN 8 THEN 'DELETE' WHEN 4 THEN 'INSERT' WHEN 20 THEN 'INSERT_UPDATE' WHEN 28 THEN 'INSERT_UPDATE_DELETE' WHEN 24 THEN 'UPDATE_DELETE' WHEN 12 THEN 'INSERT_DELETE' END || '_' || 'TRIGGER' AS object_type FROM pg_trigger AS t JOIN pg_class AS c ON t.tgrelid = c.oid JOIN pg_namespace AS ns ON ns.oid = c.relnamespace WHERE NOT t.tgrelid IN (SELECT conrelid FROM pg_constraint)), all_procedures AS (SELECT ns.nspname AS object_schema, PG_GET_USERBYID(p.proowner) AS object_owner, 'SOURCE_CODE' AS object_category, CASE WHEN p.prokind = 'f' THEN 'FUNCTION' WHEN p.prokind = 'p' THEN 'PROCEDURE' WHEN p.prokind = 'a' THEN 'AGGREGATE_FUNCTION' WHEN p.prokind = 'w' THEN 'WINDOW_FUNCTION' ELSE 'UNCATEGORIZED_PROCEDURE' END AS object_type FROM pg_proc AS p JOIN pg_namespace AS ns ON ns.oid = p.pronamespace WHERE ns.nspname <> ALL(ARRAY['pg_catalog', 'information_schema']) AND NOT ns.nspname ~ '^pg_toast'), unified_src AS (SELECT object_owner, object_category, object_type, object_schema FROM all_tables UNION ALL SELECT object_owner, object_category, object_type, object_schema FROM all_views UNION ALL SELECT object_owner, object_category, object_type, object_schema FROM all_indexes UNION ALL SELECT object_owner, object_category, object_type, object_schema FROM all_procedures UNION ALL SELECT object_owner, object_category, object_type, object_schema FROM all_constraints UNION ALL SELECT object_owner, object_category, object_type, object_schema FROM all_triggers) SELECT CHR(34) || :PKEY || CHR(34) AS pkey, CHR(34) || :DMA_SOURCE_ID || CHR(34) AS dma_source_id, CHR(34) || :DMA_MANUAL_ID || CHR(34) AS dma_manual_id, u.object_owner, u.object_category, u.object_type, u.object_schema, COUNT(*) AS object_count, CHR(34) || CURRENT_DATABASE() || CHR(34) AS database_name FROM unified_src AS u GROUP BY 1, 2, 3, 4, 5, 6, 7, 9